    label;
    @api
    name;
    @api
    messageWhenValueMissing;
    @api
    accessKey;
    @api
    autocomplete;
    @track
    _options = [];
    _helpMessage = '';
    @track
    _selectedValue;
    @track
    _variant;
    _required = false;
    _disabled = false;
    _multiple = false;
    @track
    _fieldLevelHelp;
    @track
    _size;
